/// 获取 Scene 中指定行的文本（行号从 0 开始）。
fn get_line_text(scene: &Scene, line: u32) -> Option<&str> {
    scene.sentences().get(line as usize).map(|s| s.content)
}

/// 将 UTF-16 码元偏移转换为 UTF-8 字节偏移（基于当前行文本）。
fn utf16_offset_to_utf8(line_text: &str, utf16_offset: u32) -> u32 {
    let mut utf8_pos: usize = 0;
    let mut utf16_pos: usize = 0;
    for ch in line_text.chars() {
        let ch_utf16 = ch.len_utf16();
        let ch_utf8 = ch.len_utf8();
        if utf16_pos + ch_utf16 > utf16_offset as usize {
            break;
        }
        utf16_pos += ch_utf16;
        utf8_pos += ch_utf8;
    }
    utf8_pos as u32
}

/// 将 UTF-8 字节偏移转换为 UTF-16 码元偏移（基于当前行文本）。
fn utf8_offset_to_utf16(line_text: &str, utf8_offset: u32) -> u32 {
    let target = utf8_offset as usize;
    let mut utf8_pos: usize = 0;
    let mut utf16_pos: usize = 0;
    for ch in line_text.chars() {
        let next_utf8 = utf8_pos + ch.len_utf8();
        if next_utf8 > target {
            break;
        }
        utf8_pos = next_utf8;
        utf16_pos += ch.len_utf16();
    }
    utf16_pos as u32
}

/// 将客户端传来的 Position（UTF-16）转换为服务器内部使用的 UTF-8 偏移。
/// 需要传入 Scene 对象和原始 Position.
